function normalize(text:string){return text.replace(/^\uFEFF/,'').replace(/\r\n/g,'\n').replace(/\r/g,'\n');}
function hashText(text:string){return createHash('sha256').update(normalize(text),'utf8').digest('hex');}
function readText(path:string){return readFileSync(path,'utf8');}
function isRoot(dir:string){return existsSync(join(dir,'package.json'))&&existsSync(join(dir,'shared','src','index.ts'))&&existsSync(join(dir,'server','src','rooms','Drop8Room.ts'))&&existsSync(join(dir,'client','src','GameScene.ts'));}
function ancestors(start:string){const result:string[]=[];let current=resolve(start);for(let i=0;i<12;i++){if(!result.includes(current))result.push(current);const parent=dirname(current);if(parent===current)break;current=parent;}return result;}
function findRoot(){const scriptDir=dirname(fileURLToPath(import.meta.url));for(const candidate of [...ancestors(process.cwd()),...ancestors(scriptDir)])if(isRoot(candidate))return candidate;throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 패치 파일을 프로젝트 루트에서 실행하세요.');}
function stamp(){return new Date().toISOString().replace(/[:.]/g,'-');}
function decode(change:any){return gunzipSync(Buffer.from(change.data,'base64')).toString('utf8');}
function command(label:string,cmd:string,root:string){console.log(`[${PATCH}] ${label}`);const result=spawnSync(cmd,{cwd:root,stdio:'inherit',shell:true,env:process.env});if(result.error)throw result.error;if(result.status!==0)throw new Error(`명령 실패 (exit=${result.status}): ${cmd}`);}

function importLocals(text:string){
  const locals:string[]=[];
  const named=/import\s+(?:type\s+)?\{([\s\S]*?)\}\s+from\s+['"][^'"]+['"]/g;
  for(const match of text.matchAll(named))for(const raw of match[1].split(',')){const item=raw.trim().replace(/^type\s+/,'');if(!item)continue;const parts=item.split(/\s+as\s+/);locals.push((parts[1]??parts[0]).trim());}
  const defaults=/^import\s+(?!type\b)([A-Za-z_$][\w$]*)\s*(?:,|from)/gm;
  for(const match of text.matchAll(defaults))locals.push(match[1]);
  const namespaces=/^import\s+\*\s+as\s+([A-Za-z_$][\w$]*)\s+from/gm;
  for(const match of text.matchAll(namespaces))locals.push(match[1]);
  return locals;
}
function validateDuplicateDeclarations(text:string,file:string){
  const names=[...importLocals(text)];
  const declarations=/^(?:export\s+)?(?:declare\s+)?(?:const|let|var|function|class|interface|type|enum)\s+([A-Za-z_$][\w$]*)/gm;
  for(const match of text.matchAll(declarations))names.push(match[1]);
  const seen=new Set<string>();
  for(const name of names){if(seen.has(name))throw new Error(`${file}: 최상위 식별자 '${name}' 중복 선언`);seen.add(name);}
}
function validateRelativeImports(root:string,relative:string,text:string){
  const pattern=/(?:from\s+|import\s*\()\s*['"](\.[^'"]+)['"]/g;
  for(const match of text.matchAll(pattern)){
    const spec=match[1];let target=resolve(dirname(join(root,relative)),spec);
    const candidates=[target];
    if(extname(target)==='.js')candidates.push(target.slice(0,-3)+'.ts');
    if(!extname(target))candidates.push(target+'.ts',target+'.tsx',join(target,'index.ts'));
    if(!candidates.some((candidate)=>existsSync(candidate)))throw new Error(`${relative}: 상대 import 확인 실패 '${spec}'`);
  }
}
